namespace test.Inner
  import std
  data S1 {
    cmp  s: S
    cmp  a: String
  }
  union S { String | S1 }
namespace test.Outer
  import std
  import test.Inner
  data BI {
    cmp  inner: Any
  }
  data S1 {
    cmp  b: B
    cmp  s: S
  }
  union S { String | S1 }
--- Asm Transform ---
namespace test
  asm-transform Inner {
    S: when {
      0 == $alternative -> with(child[0]) $self
      1 == $alternative -> with(child[0]) $self
    }
    S1: test.Inner.S1() {
      s := child[0]
      a := child[1]
    }
    a: $self
  }
  asm-transform Outer {
    B: BI() {
      inner := child[1]
    }
    S: when {
      0 == $alternative -> with(child[0]) $self
      1 == $alternative -> with(child[0]) $self
    }
    S1: test.Outer.S1() {
      b := child[0]
      s := child[1]
    }
    b: $self
    c: $self
    d: $self
  }
