    S: child[0] as String
    S1: (    child[0] + child[1]) as String
    a: $self
  }
  asm-transform Outer {
    B: BI() {
      inner := child[1]
    }
    S: when {
      0 == $alternative -> with(child[0]) $self
      1 == $alternative -> with(child[0]) $self
    }
    S1: test.Outer.S1() {
      b := child[0]
      s := child[1]
    }
    b: $self
    c: $self
    d: $self
  }
